 1	import { type FC, useCallback } from 'react';
 2	import { canPlanStart } from 'src/plans/details/components/PlanStatus/utils/utils';
 3	import usePlanSourceProvider from 'src/plans/details/hooks/usePlanSourceProvider';
 4	import { getPlanMigrationType } from 'src/plans/details/utils/utils';
 5	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import ModalForm from '@components/ModalForm/ModalForm';
 8	import type { V1beta1Plan } from '@kubev2v/types';
 9	import { Stack, StackItem } from '@patternfly/react-core';
10	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
11	import { getName } from '@utils/crds/common/selectors';
12	
13	import { migrationModalMessage, startPlanMigration } from './utils/utils';
14	
15	type PlanStartMigrationModalProps = {
16	  plan: V1beta1Plan;
17	  title: string;
18	};
19	
20	const PlanStartMigrationModal: FC<PlanStartMigrationModalProps> = ({ plan, title }) => {
21	  const { t } = useForkliftTranslation();
22	  const { trackEvent } = useForkliftAnalytics();
23	
24	  const name = getName(plan);
25	  const migrationType = getPlanMigrationType(plan);
26	  const { sourceProvider } = usePlanSourceProvider(plan);
27	
28	  const onStart = useCallback(async () => {
29	    return startPlanMigration(plan, trackEvent, sourceProvider?.spec?.type);
30	  }, [plan, trackEvent, sourceProvider?.spec?.type]);
31	
32	  const migrationMessage = migrationModalMessage(migrationType);
33	
34	  return (
35	    <ModalForm
36	      title={t('{{title}} migration', { title })}
37	      onConfirm={onStart}
38	      confirmLabel={t('{{title}}', { title })}
39	      isDisabled={!canPlanStart(plan)}
40	    >
41	      <Stack hasGutter>
42	        <StackItem>
43	          <ForkliftTrans>
44	            <StackItem>
45	              Start the {migrationType} migration for plan{' '}
46	              <strong className="co-break-word">{name}</strong>?
47	            </StackItem>
48	            <StackItem>{migrationMessage}</StackItem>
49	          </ForkliftTrans>
50	        </StackItem>
51	      </Stack>
52	    </ModalForm>
53	  );
54	};
55	
56	export default PlanStartMigrationModal;

